  1→#!/usr/bin/env node
  2→import { readFileSync } from "node:fs";
  3→import { dirname, resolve } from "node:path";
  4→import { fileURLToPath } from "node:url";
  5→
  6→// ── Arg parsing helpers ──────────────────────────────────────────────
  7→const argv = process.argv.slice(2);
  8→
  9→function flag(name) {
 10→  const i = argv.indexOf(`--${name}`);
 11→  if (i === -1) return undefined;
 12→  const val = argv[i + 1];
 13→  return val && !val.startsWith("--") ? val : true;
 14→}
 15→
 16→function hasFlag(name) {
 17→  return argv.includes(`--${name}`);
 18→}
 19→
 20→function jsonFlag(name) {
 21→  const v = flag(name);
 22→  if (v === undefined || v === true) return undefined;
 23→  try { return JSON.parse(v); } catch { errExit(`Invalid JSON for --${name}`, "NOTION_VALIDATION", `Ensure --${name} is valid JSON`); }
 24→}
 25→
 26→// ── Output helpers ───────────────────────────────────────────────────
 27→function ok(data) { process.stdout.write(JSON.stringify(data, null, 2) + "\n"); process.exit(0); }
 28→function errExit(error, code, hint) {
 29→  process.stderr.write(JSON.stringify({ error, code, hint }) + "\n");
 30→  process.exit(1);
 31→}
 32→
 33→// ── Auth resolution ──────────────────────────────────────────────────
 34→function resolveAuth() {
 35→  if (process.env.NOTION_API_KEY) return process.env.NOTION_API_KEY;
 36→  const __dirname = dirname(fileURLToPath(import.meta.url));
 37→  let dir = __dirname;
 38→  for (let i = 0; i < 5; i++) {
 39→    try {
 40→      const env = readFileSync(resolve(dir, ".env"), "utf8");
 41→      const m = env.match(/^NOTION_API_KEY=(.+)$/m);
 42→      if (m) return m[1].trim();
 43→    } catch { /* not found, walk up */ }
 44→    dir = dirname(dir);
 45→  }
 46→  errExit("No Notion API key found", "NOTION_AUTH_MISSING", "Set NOTION_API_KEY in .env or environment");
 47→}
 48→
 49→// ── Notion URL → UUID ────────────────────────────────────────────────
 50→function extractId(input) {
 51→  const hex = input.replace(/-/g, "").match(/([0-9a-f]{32})(?:[?#]|$)/i);
 52→  if (hex) {
 53→    const h = hex[1];
 54→    return `${h.slice(0,8)}-${h.slice(8,12)}-${h.slice(12,16)}-${h.slice(16,20)}-${h.slice(20)}`;
 55→  }
 56→  if (/^[0-9a-f-]{32,36}$/i.test(input)) {
 57→    const bare = input.replace(/-/g, "");
 58→    return `${bare.slice(0,8)}-${bare.slice(8,12)}-${bare.slice(12,16)}-${bare.slice(16,20)}-${bare.slice(20)}`;
 59→  }
 60→  return input;
 61→}
 62→
 63→// ── Raw Notion API client (no SDK — avoids v5.9 validation bugs) ─────
 64→const NOTION_API = "https://api.notion.com/v1";
 65→const NOTION_VERSION = "2022-06-28";
 66→
 67→async function notionFetch(path, { method = "GET", body } = {}) {
 68→  const opts = {
 69→    method,
