 71→      "Authorization": `Bearer ${key}`,
 72→      "Notion-Version": NOTION_VERSION,
 73→      "Content-Type": "application/json",
 74→    },
 75→  };
 76→  if (body) opts.body = JSON.stringify(body);
 77→
 78→  const res = await fetch(`${NOTION_API}${path}`, opts);
 79→  const data = await res.json();
 80→
 81→  if (!res.ok) {
 82→    const err = new Error(data.message || `Notion API error ${res.status}`);
 83→    err.status = res.status;
 84→    err.body = data;
 85→    throw err;
 86→  }
 87→  return data;
 88→}
