 90→// ── Retry with backoff (for 429) ─────────────────────────────────────
 91→async function withRetry(fn, retries = 3) {
 92→  for (let i = 0; i <= retries; i++) {
 93→    try { return await fn(); } catch (e) {
 94→      if (e.status === 429 && i < retries) {
 95→        const wait = e.body?.retry_after ? e.body.retry_after * 1000 : 1000 * Math.pow(2, i);
 96→        await new Promise(r => setTimeout(r, wait));
 97→        continue;
 98→      }
 99→      throw e;
100→    }
